#include <bits/stdc++.h>
using namespace std;
struct Point{
    int x,y;
}p[11][1025];
int n,m,f[15],g[5003][5003],len[5003],del[12][1025];
void des(int x,int y){
    if(del[x][y] || x>n)
        return;
    del[x][y]=1;
    des(x+1,y*2-1);
    des(x+1,y*2);
}
void fill(int u1,int v1,int u2,int v2,int tp){
    if(tp==2){
        int i=u1+1,j=v1-1;
        while(i<u2 && j>v2)
            g[i][j]=tp,len[i]=max(len[i],j),i++,j--;
    }else{
        int i=u1+1,j=v1+1;
        while(i<u2 && j<v2)
            g[i][j]=tp,len[i]=max(len[i],j),i++,j++;
    }
}
void setg(int x,int y){
    if(del[x][y])
        return;
    g[p[x][y].x][p[x][y].y]=1,len[p[x][y].x]=max(len[p[x][y].x],p[x][y].y);
    if(!del[x+1][y*2-1] && x<n){
        fill(p[x][y].x,p[x][y].y,p[x+1][y*2-1].x,p[x+1][y*2-1].y,2);
        setg(x+1,y*2-1);
    }
    if(!del[x+1][y*2] && x<n){
        fill(p[x][y].x,p[x][y].y,p[x+1][y*2].x,p[x+1][y*2].y,3);
        setg(x+1,y*2);
    }
}
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<15;i++)
        if(i<=2)
            f[i]=i+1;
        else
            f[i]=f[i-1]*2;
    p[1][1]={1,f[n]};
    for(int i=2;i<=n;i++)
        for(int j=1;j<=1<<i-1;j++)
            if(j%2)
                p[i][j]={p[i-1][(j+1)/2].x+f[n-i+1],p[i-1][(j+1)/2].y-f[n-i+1]};
            else
                p[i][j]={p[i-1][(j+1)/2].x+f[n-i+1],p[i-1][(j+1)/2].y+f[n-i+1]};
    /*for(int i=1;i<=n;i++){
    	printf("%d ",p[i][1].x);
    	for(int j=1;j<=1<<i-1;j++)
    		printf("%d ",p[i][j].y);
    	printf("\n");
    }*/
    for(int i=1;i<=m;i++){
        int u,v;
        scanf("%d%d",&u,&v);
        des(u,v);
    }
    setg(1,1);
    for(int i=1;i<=p[n][1].x;i++){
        for(int j=1;j<=len[i];j++){
            if(g[i][j]==0)
                printf(" ");
            else if(g[i][j]==1)
                printf("o");
            else if(g[i][j]==2)
                printf("/");
            else
                printf("%c",char(92));
        }
        printf("\n");
    }
    return 0;
}
